import React, { useState } from "react";
import { motion } from "framer-motion";
import {
  Star,
  Heart,
  Users,
  Sparkles,
  ChevronRight,
  Award,
} from "lucide-react";
import { Link } from "react-router-dom";

const services = [
  {
    id: 1,
    title: "Wedding Sangeet",
    icon: Heart,
    tagline: "Cinematic Choreography for Your Special Day",
    image:
      "https://images.unsplash.com/photo-1519671482749-fd09be7ccebf?auto=format&fit=crop&w=800&q=80",
    desc: "Transform your wedding celebration into an unforgettable visual spectacle with our bespoke choreography.",
    features: [
      "Couples choreography",
      "Family group performances",
      "Thematic concepts",
      "Professional dancers",
      "Full production support",
    ],
    highlights:
      "We create cinematic moments that tell your love story through dance. From intimate couple dances to grand ensemble performances, every move is tailored to your vision.",
    pricing: "Custom quotes",
  },
  {
    id: 2,
    title: "Corporate Events",
    icon: Users,
    tagline: "Elevate Your Brand Presence",
    image:
      "https://images.unsplash.com/photo-1552664730-d307ca884978?auto=format&fit=crop&w=800&q=80",
    desc: "Professional performances for product launches, award nights, and corporate galas.",
    features: [
      "Product launch performances",
      "Team building activities",
      "Flash mob experiences",
      "Brand storytelling",
      "Technical production",
    ],
    highlights:
      "Impress your audience with high-energy, sophisticated performances that align perfectly with your brand message and corporate values.",
    pricing: "Custom quotes",
  },
  {
    id: 3,
    title: "Music Videos & Production",
    icon: Sparkles,
    tagline: "Professional Artistic Direction",
    image:
      "https://images.unsplash.com/photo-1514525253161-7a46d19cd819?auto=format&fit=crop&w=800&q=80",
    desc: "Stage shows, music videos, and cinematic choreography for professional productions.",
    features: [
      "Music video choreography",
      "TV production",
      "Theater shows",
      "Concert performances",
      "Post-production consultation",
    ],
    highlights:
      "From concept to final cut, we bring professional-grade choreography to your creative vision with expertise in camera angles, timing, and artistic direction.",
    pricing: "Custom quotes",
  },
  {
    id: 4,
    title: "Private Sessions",
    icon: Award,
    tagline: "One-on-One Professional Coaching",
    image:
      "https://images.unsplash.com/photo-1534294-4f3d1f1a0a4b?auto=format&fit=crop&w=800&q=80",
    desc: "Personalized choreography and performance coaching for individuals and small groups.",
    features: [
      "Custom choreography",
      "Performance coaching",
      "Technical refinement",
      "Flexible scheduling",
      "One-on-one attention",
    ],
    highlights:
      "Get dedicated expert guidance tailored to your unique needs, whether preparing for an audition, event, or perfecting your craft.",
    pricing: "Custom quotes",
  },
];

const ProServices = () => {
  const [activeService, setActiveService] = useState(null);

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.15,
        delayChildren: 0.2,
      },
    },
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 40 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.6 },
    },
  };

  return (
    <div className="pt-24 pb-24 px-6 lg:px-12 overflow-hidden">
      {/* Decorative Backgrounds */}
      <div className="fixed inset-0 -z-10">
        <div className="absolute top-0 right-0 w-96 h-96 bg-gold/3 rounded-full blur-3xl" />
        <div className="absolute bottom-1/3 left-0 w-96 h-96 bg-gold/2 rounded-full blur-3xl" />
      </div>

      {/* Header Section */}
      <section className="max-w-7xl mx-auto mb-24">
        <motion.div
          initial={{ opacity: 0, y: 40 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          className="text-center"
        >
          <p className="text-gold tracking-[0.4em] uppercase text-xs font-montserrat font-light mb-4">
            Professional Services
          </p>
          <h1 className="text-5xl md:text-6xl lg:text-7xl font-cinzel font-bold mb-8">
            Pro Services
          </h1>
          <div className="h-1 w-40 bg-gradient-to-r from-transparent via-gold to-transparent mx-auto mb-8" />
          <p className="max-w-3xl mx-auto text-ivory/70 text-lg font-light leading-relaxed">
            Elevate your special moments with world-class choreography and
            artistic direction. From weddings to corporate events, we bring
            professional excellence to every production.
          </p>
        </motion.div>
      </section>

      {/* Services Grid */}
      <section className="max-w-7xl mx-auto mb-24">
        <motion.div
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true }}
          className="grid md:grid-cols-2 gap-8"
        >
          {services.map((service) => {
            const Icon = service.icon;
            const isActive = activeService === service.id;

            return (
              <motion.div
                key={service.id}
                variants={cardVariants}
                whileHover={{ y: -15 }}
                onClick={() => setActiveService(isActive ? null : service.id)}
                className="group relative overflow-hidden rounded-2xl border border-gold/20 hover:border-gold/60 transition-all duration-300 cursor-pointer"
              >
                {/* Background Image */}
                <div className="absolute inset-0 h-96">
                  <img
                    src={service.image}
                    alt={service.title}
                    className="w-full h-full object-cover transition-all duration-700 group-hover:scale-110 grayscale group-hover:grayscale-0"
                  />
                  <div className="absolute inset-0 bg-gradient-to-b from-charcoal/20 via-charcoal/60 to-charcoal/80 group-hover:via-charcoal/80 transition-all duration-300" />
                </div>

                {/* Content Container */}
                <motion.div
                  animate={{ height: isActive ? "auto" : "400px" }}
                  transition={{ duration: 0.3 }}
                  className="relative flex flex-col h-96 group-hover:h-auto"
                >
                  {/* Top Section */}
                  <div className="p-8 flex flex-col justify-between h-96 group-hover:h-auto relative z-10">
                    <div>
                      <motion.div
                        whileHover={{ scale: 1.1 }}
                        className="w-12 h-12 bg-gold/20 border border-gold/40 rounded-lg flex items-center justify-center mb-4 group-hover:bg-gold/30 transition-all duration-300"
                      >
                        <Icon className="w-6 h-6 text-gold" />
                      </motion.div>

                      <h3 className="text-3xl font-cinzel font-bold text-white mb-2">
                        {service.title}
                      </h3>
                      <p className="text-gold/80 text-sm font-montserrat uppercase tracking-widest font-light mb-4">
                        {service.tagline}
                      </p>
                      <div className="h-0.5 w-12 bg-gradient-to-r from-gold to-transparent mb-6" />
                    </div>

                    <div className="space-y-4">
                      <p className="text-ivory/80 font-light leading-relaxed">
                        {service.desc}
                      </p>
                      <motion.div
                        animate={{
                          opacity: isActive ? 1 : 0,
                          height: isActive ? "auto" : 0,
                        }}
                        transition={{ duration: 0.3 }}
                        className="overflow-hidden space-y-6"
                      >
                        {/* Features List */}
                        <div>
                          <h4 className="text-gold font-cinzel text-sm uppercase tracking-widest font-semibold mb-4">
                            What's Included
                          </h4>
                          <ul className="space-y-2">
                            {service.features.map((feature, idx) => (
                              <li
                                key={idx}
                                className="flex items-center space-x-3 text-ivory/70 text-sm font-light"
                              >
                                <div className="w-1.5 h-1.5 rounded-full bg-gold/60" />
                                <span>{feature}</span>
                              </li>
                            ))}
                          </ul>
                        </div>

                        {/* Highlights */}
                        <div className="p-6 bg-charcoal/50 border border-gold/20 rounded-lg">
                          <p className="text-ivory/80 text-sm font-light leading-relaxed">
                            {service.highlights}
                          </p>
                        </div>

                        {/* CTA */}
                        <div className="flex items-center justify-between pt-4 border-t border-gold/20">
                          <p className="text-gold tracking-widest uppercase text-xs font-semibold">
                            {service.pricing}
                          </p>
                          <Link
                            to="/connect"
                            className="text-gold hover:text-ivory transition-colors text-sm uppercase tracking-widest font-bold border-b border-gold hover:border-ivory pb-1"
                          >
                            Inquire →
                          </Link>
                        </div>
                      </motion.div>

                      {/* Expand Indicator */}
                      <motion.div
                        animate={{ rotate: isActive ? 180 : 0 }}
                        className="absolute bottom-4 right-4"
                      >
                        <ChevronRight className="w-6 h-6 text-gold/60" />
                      </motion.div>
                    </div>
                  </div>
                </motion.div>
              </motion.div>
            );
          })}
        </motion.div>
      </section>

      {/* Process Section */}
      <section className="max-w-7xl mx-auto mb-24">
        <motion.div
          initial={{ opacity: 0, y: 40 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="text-center mb-16"
        >
          <p className="text-gold tracking-[0.4em] uppercase text-xs font-montserrat font-light mb-4">
            How We Work
          </p>
          <h2 className="text-4xl md:text-5xl font-cinzel font-bold mb-8">
            Our Creative Process
          </h2>
          <div className="h-1 w-40 bg-gradient-to-r from-transparent via-gold to-transparent mx-auto" />
        </motion.div>

        <div className="grid md:grid-cols-4 gap-6">
          {[
            {
              step: "01",
              title: "Consultation",
              desc: "Understand your vision and goals",
            },
            {
              step: "02",
              title: "Concept Development",
              desc: "Create a tailored artistic concept",
            },
            {
              step: "03",
              title: "Choreography",
              desc: "Develop stunning choreography",
            },
            {
              step: "04",
              title: "Production",
              desc: "Execute with professional precision",
            },
          ].map((item, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1 }}
              whileHover={{ y: -10 }}
              className="relative p-8 border border-gold/20 hover:border-gold/60 rounded-xl bg-charcoal-light/30 backdrop-blur-sm transition-all duration-300 group"
            >
              <div className="absolute -top-6 left-8 w-12 h-12 bg-gold rounded-full flex items-center justify-center text-charcoal font-bold text-lg border-4 border-charcoal group-hover:shadow-luxury-gold transition-all duration-300">
                {item.step}
              </div>

              <div className="pt-8">
                <h3 className="text-xl font-cinzel font-bold text-ivory mb-3">
                  {item.title}
                </h3>
                <p className="text-ivory/60 text-sm font-light leading-relaxed">
                  {item.desc}
                </p>
              </div>

              {/* Connecting Arrow */}
              {index < 3 && (
                <div className="hidden md:block absolute top-1/2 -right-6 w-6 h-0.5 bg-gradient-to-r from-gold/60 to-transparent" />
              )}
            </motion.div>
          ))}
        </div>
      </section>

      {/* Portfolio Highlights */}
      <section className="max-w-7xl mx-auto mb-24">
        <motion.div
          initial={{ opacity: 0, y: 40 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="text-center mb-16"
        >
          <p className="text-gold tracking-[0.4em] uppercase text-xs font-montserrat font-light mb-4">
            Our Work
          </p>
          <h2 className="text-4xl md:text-5xl font-cinzel font-bold mb-8">
            Portfolio Highlights
          </h2>
          <div className="h-1 w-40 bg-gradient-to-r from-transparent via-gold to-transparent mx-auto" />
        </motion.div>

        <div className="grid md:grid-cols-3 gap-8">
          {[
            {
              title: "50+ Weddings",
              desc: "Choreographed celebrations across cities",
              stat: "500+",
            },
            {
              title: "25+ Corporate Events",
              desc: "Successful brand activations and launches",
              stat: "99%",
            },
            {
              title: "15+ Productions",
              desc: "Music videos, shows, and performances",
              stat: "15+",
            },
          ].map((item, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, scale: 0.9 }}
              whileInView={{ opacity: 1, scale: 1 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1 }}
              whileHover={{ y: -10 }}
              className="relative p-12 border border-gold/20 hover:border-gold/60 rounded-xl text-center backdrop-blur-sm transition-all duration-300 group overflow-hidden"
            >
              <div className="absolute top-0 right-0 w-40 h-40 bg-gold/5 rounded-full blur-3xl group-hover:bg-gold/10 transition-all duration-300" />

              <div className="relative z-10">
                <h3 className="text-4xl md:text-5xl font-cinzel font-bold text-gold-gradient mb-4">
                  {item.stat}
                </h3>
                <h4 className="text-xl font-cinzel font-bold text-ivory mb-3">
                  {item.title}
                </h4>
                <p className="text-ivory/60 text-sm font-light">{item.desc}</p>
              </div>
            </motion.div>
          ))}
        </div>
      </section>

      {/* Why Choose DOD */}
      <section className="max-w-7xl mx-auto mb-24">
        <motion.div
          initial={{ opacity: 0, y: 40 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="text-center mb-16"
        >
          <p className="text-gold tracking-[0.4em] uppercase text-xs font-montserrat font-light mb-4">
            Why Partner With Us
          </p>
          <h2 className="text-4xl md:text-5xl font-cinzel font-bold mb-8">
            What Sets DOD Apart
          </h2>
          <div className="h-1 w-40 bg-gradient-to-r from-transparent via-gold to-transparent mx-auto" />
        </motion.div>

        <div className="grid md:grid-cols-3 gap-8">
          {[
            {
              icon: Star,
              title: "Expert Team",
              desc: "Industry professionals with global experience and award recognition",
            },
            {
              icon: Heart,
              title: "Artistic Vision",
              desc: "Creative storytelling that resonates with your audience",
            },
            {
              icon: Award,
              title: "Premium Execution",
              desc: "Technical excellence in choreography, production, and performance",
            },
          ].map((item, index) => {
            const Icon = item.icon;
            return (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 20 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ delay: index * 0.1 }}
                whileHover={{ y: -10 }}
                className="p-8 border border-gold/20 hover:border-gold/60 rounded-xl bg-charcoal-light/30 backdrop-blur-sm transition-all duration-300 text-center group"
              >
                <div className="w-16 h-16 bg-gold/10 border border-gold/30 rounded-lg mx-auto mb-6 flex items-center justify-center group-hover:bg-gold/20 transition-all duration-300">
                  <Icon className="w-8 h-8 text-gold" />
                </div>
                <h3 className="text-xl font-cinzel font-bold text-ivory mb-3">
                  {item.title}
                </h3>
                <p className="text-ivory/60 text-sm font-light leading-relaxed">
                  {item.desc}
                </p>
              </motion.div>
            );
          })}
        </div>
      </section>

      {/* Final CTA */}
      <motion.section
        initial={{ opacity: 0, y: 40 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true }}
        className="max-w-5xl mx-auto py-20 px-12 bg-gradient-to-r from-charcoal-light/50 to-charcoal/50 border-2 border-gold/30 rounded-2xl text-center backdrop-blur-md"
      >
        <h2 className="text-4xl md:text-5xl font-cinzel font-bold mb-6">
          Ready to Create Magic?
        </h2>
        <p className="text-ivory/70 text-lg font-light max-w-3xl mx-auto mb-12 leading-relaxed">
          Let's transform your vision into an unforgettable experience. Whether
          it's a wedding, corporate event, or production, we're ready to bring
          your story to life through the art of movement.
        </p>

        <div className="flex flex-col sm:flex-row items-center justify-center gap-6">
          <Link
            to="/connect"
            className="group relative px-10 py-4 overflow-hidden border-2 border-gold transition-all duration-300 hover:shadow-luxury-gold rounded-lg"
          >
            <span className="absolute inset-0 bg-gold translate-y-full group-hover:translate-y-0 transition-transform duration-300 z-0" />
            <span className="relative z-10 text-gold group-hover:text-charcoal transition-colors uppercase tracking-widest text-sm font-bold flex items-center space-x-2">
              <span>Book a Consultation</span>
              <ChevronRight size={18} />
            </span>
          </Link>

          <button className="px-10 py-4 border-2 border-gold/40 hover:border-gold text-ivory hover:text-gold transition-all duration-300 rounded-lg uppercase tracking-widest text-sm font-bold">
            View Portfolio
          </button>
        </div>
      </motion.section>
    </div>
  );
};

export default ProServices;
